$2C23> A9 07:	LDA #$07	;
$2C25> 85 83:	STA $83		; difficulty level = 7
$2C27> A9 02:	LDA #$02	;
$2C29> 85 7C:	STA $7C		; speed timer reload = 2
$2C2B> 85 7D:	STA $7D		; speed countdown = 2
