$2C2F> A9 00:	LDA #$00	;
$2C31> 85 8E:	STA $8E		; crash flag = 0 (alive)
$2C33> A9 02:	LDA #$02	;
$2C35> 85 92:	STA $92		; speed level = 2
$2C37> A9 00:	LDA #$00	;
