$310C> 20 1731:	JSR $3117	; play 32 cycles at this period
$310F> A9 40:	LDA #$40	; low tone period
$3111> 85 21:	STA $21		;
$3113> 20 1731:	JSR $3117	; play 32 cycles at this period
$3116> 60:		RTS		;
