$3126> 20 E92B:	JSR $2BE9	; AND mask
$3129> C6 23:	DEC $23		;
$312B> D0 FC:	BNE $3129		; delay loop
$312D> A9 01:	LDA #$01	; set bit 0 (rising edge)
$312F> 20 EE2B:	JSR $2BEE	; OR mask
$3132> A5 21:	LDA $21		;
$3134> 85 23:	STA $23		; delay counter = period
$3136> C6 23:	DEC $23		;
$3138> D0 FC:	BNE $3136		;
$313A> 60:		RTS		;
